var e=[{id:`L2_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_CA_SPECIAL`,text:{KOREA:`이걸로 계약 성립이네! 마법소녀의 영원한 시조ㅇ… 아니, 사랑의 파트너가 된 걸 축하해-`,JPN:`これで契約成立ね！　魔法少女の永遠のしも……じゃなかった、愛のパートナーになったこと、おめでとう！`,ENG:`The contract is sealed! Congratulations on becoming the magical girl's eternal serva– I mean, partner of love!`,TWN:`這樣就完成簽約囉！恭喜你成為魔法少女永遠的僕…沒有啦，是愛的夥伴。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_CA_SPECIAL`,face:`UNIT_IDLE`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`ROSARIA_FALLEN_CA_SPECIAL`,text:{KOREA:`세계평화를 위해, 앞으로도 이 로자리아님의 마법에너지 공급원으로서 부지런히 노력해줘?`,JPN:`世界平和のため、これからもこのロザリア様の魔法エネルギー供給源として絶えず努力するのよ？`,ENG:`I expect you to continue working hard to preserve world peace and provide me with magical energy!`,TWN:`以後我負責守護世界和平，而你就是我的魔法力量來源，要努力認真喔。`},stage:{bg:`LIFETIME`,bgm:`CUTSCENE_HOPE`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`ROSARIA_FALLEN_CA_SPECIAL`,face:`UNIT_PRIDE`},R:null}}}];export{e as default};